# Populate status dimension from the parameter string.
sRemaining = sStatusList;
nSequence = 10;
While(Long(sRemaining) > 0);
  nDelimPos = Scan('|', sRemaining, 1);
  If(nDelimPos = 0);
    sCurrent = Trim(sRemaining);
    sRemaining = '';
  Else;
    sCurrent = Trim(SubSt(sRemaining, 1, nDelimPos - 1));
    sRemaining = SubSt(sRemaining, nDelimPos + 1, Long(sRemaining) - nDelimPos);
  EndIf;

  If(sCurrent @<> '');
    If(DimensionElementExists(sDimStatus, sCurrent) = 0);
      DimensionElementInsert(sDimStatus, '', sCurrent, 'N');
      DimensionElementComponentAdd(sDimStatus, 'All Statuses', sCurrent, 1);
    EndIf;

    AttrPutN(nSequence, sDimStatus, sCurrent, 'Sequence');
    If(sCurrent @= 'Archived');
      AttrPutS('Y', sDimStatus, sCurrent, 'IsTerminal');
    Else;
      AttrPutS('N', sDimStatus, sCurrent, 'IsTerminal');
    EndIf;
    nSequence = nSequence + 10;
  EndIf;
End;

